<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; class Order extends Model { protected $fillable = ['user_id', 'service_id', 'link', 'quantity', 'price', 'status', 'progress', 'external_order_id', 'notes']; protected $casts = ['notes' => 'array']; public function user() { return $this->belongsTo(User::class); } public function service() { return $this->belongsTo(Service::class); } public function tickets() { return $this->hasMany(Ticket::class); } }